  function render(){ const q=(search.value||'').toLowerCase().trim(); groups.innerHTML=NAV.groups.map(g=>{ const cards=NAV.pages.filter(p=>(p.group||p.section)===g).filter(p=>!q||`${p.title} ${p.why||p.summary||''} ${p.group||''}`.toLowerCase().includes(q)); if(!cards.length)return ''; return `<article class="nav38-group"><h3>${g}</h3><div>${cards.map(p=>`<a href="${base+p.href}"><strong>${p.title}</strong><span>${p.why||p.summary||''}</span><em>${p.time||''} · ${(p.audience||['all']).join(' · ')}</em></a>`).join('')}</div></article>`; }).join('')||'<p class="nav38-empty">No matching page.</p>'; }
